【画像适配性分析 — 评估心理学驱动与目标用户的匹配度】

请评估内容的心理学驱动策略与目标用户画像的匹配程度。

目标用户画像：
<<portrait>>

内容主导心理：
<<step_psychology_dimension_analysis.dominant_psychology>>

心理学维度分析：
<<step_psychology_dimension_analysis>>

请输出JSON：

{
  "portrait_fit_score": 0-100的匹配度分数,
  "fit_analysis": {
    "identity_match": {
      "score": 分数,
      "detail": "内容身份定位与画像身份的匹配程度"
    },
    "pain_point_trigger": {
      "score": 分数,
      "detail": "痛点触发与画像痛点的匹配程度"
    },
    "psychology_approach": {
      "score": 分数,
      "detail": "心理学策略与用户心理特征的匹配程度"
    },
    "content_tone": {
      "score": 分数,
      "detail": "内容语气与用户偏好的匹配程度"
    }
  },
  "misalignment_issues": [
    {
      "issue": "不匹配问题描述",
      "location": "问题所在位置（封面/正文/CTA）",
      "suggestion": "调整建议"
    }
  ],
  "recommended_psychology_boost": "推荐的心理学增强方向"
}
